#include<bits/stdc++.h>
using namespace std;
int a[10],A,B,C,flag,x[3],ans;
int main(void){
	cin>>A>>B>>C;
	for(int i=1;i<=1000/C;i++){
		memset(a,0,sizeof(a));
		x[0]=i*A;
		x[1]=i*B;
		x[2]=i*C; 
		if(x[1]>999||x[2]>999)break;
		for(int j=0;j<3;j++){
			int mok=x[j];
			while(x[j]){
				a[x[j]%10]++;
				x[j]/=10;
			}x[j]=mok;
		}
        for(int j=1;j<=9;j++)if(a[j]!=1){flag=1;break;}
        if(flag==1){flag=0;continue;}
        for(int j=1;j<=9;j++)a[j]=0;
        for(int j=0;j<3;j++)cout<<x[j]<<' ';ans=1;
        cout<<"\n";
    }
    if(!ans)cout <<"No!!!";
    return false;
}
